282	            ptr_C(args.ptr_C),
283	            ptr_D(args.ptr_D)
284	        {
285	        }
286	
287	        CUTLASS_HOST_DEVICE
288	        void update(Arguments const& args, void* workspace = nullptr, int tile_count = 0)
289	        {
290	
291	            problem_visitor = typename ProblemVisitor::Params(
292	                args.total_rows_before_expert, args.gemm_n, args.gemm_k, args.problem_count, workspace, tile_count);
293	            threadblock_count = args.threadblock_count;
294	            output_op         = args.output_op;
295	            ptr_A             = args.ptr_A;
296	            ptr_B             = args.ptr_B;
297	            weight_scales     = args.weight_scales;
298	            ptr_C             = args.ptr_C;
299	            ptr_D             = args.ptr_D;
300	        }
301	    };
302	
303	    /// Shared memory storage structure
304	    union SharedStorage {
305	        typename ProblemVisitor::SharedStorage problem_visitor;
306	        typename Mma::SharedStorage            main_loop;
307	        typename Epilogue::SharedStorage       epilogue;
308	    };
309	
310	public:
311	    //
312	    // Methods
313	    //
314	
315	    CUTLASS_DEVICE
316	    MoeFCGemm() {}
317	
318	    /// Determines whether kernel satisfies alignment
319	    static Status can_implement(cutlass::gemm::GemmCoord const& problem_size)
320	    {
321	        return Status::kSuccess;
322	    }
323	
324	    static Status can_implement(Arguments const& args)
325	    {
326	        if (platform::is_same<uint8_t, ElementB>::value || platform::is_same<uint4b_t, ElementB>::value) {
327	            if (args.weight_scales == nullptr) {
328	                CUTLASS_TRACE_HOST("MoeFCGemm::can_implement() - weight scales are required for uint8_t and uint4b_t");
329	                return Status::kInvalid;
330	            }
331	        }
332	        else if (args.weight_scales != nullptr) {
333	            CUTLASS_TRACE_HOST(
334	                "MoeFCGemm::can_implement() - weight scales are ignored for all types except uint8_t and uint4b_t");
335	            return Status::kInvalid;
336	        }
337	        return Status::kSuccess;
338	    }
339	
340	    static size_t get_extra_workspace_size(Arguments const& args, cutlass::gemm::GemmCoord const& grid_tiled_shape)
341	    {
342	
343	        return 0;
344	    }
345	
346	    // The dummy template parameter is not used and exists so that we can compile this code using
347	    // a standard earlier than C++17. Prior to C++17, fully specialized templates HAD to exists in
348	    // a namespace
349	    template<bool B, typename dummy = void>
350	    struct KernelRunner {
351	        CUTLASS_DEVICE
352	        static void run_kernel(Params const& params, SharedStorage& shared_storage)
353	        {
354	            CUTLASS_NOT_IMPLEMENTED();
355	        }
356	    };
357	
358	    template<typename dummy>
359	    struct KernelRunner<true, dummy> {
360	        CUTLASS_DEVICE
361	        static void run_kernel(Params const& params, SharedStorage& shared_storage)
362	        {
363	            //
364	            // These types shadow the type-level definitions and support the ability to implement
365	            // a 'transposed' GEMM that computes the transposed problems.
366	            //
367	            using ElementA                   = typename Mma::IteratorA::Element;
368	            using LayoutA                    = typename Mma::IteratorA::Layout;
369	            using ElementB                   = typename Mma::IteratorB::Element;
370	            using LayoutB                    = typename Mma::IteratorB::Layout;
371	            using ElementC                   = typename Epilogue::OutputTileIterator::Element;
372	            using LayoutC                    = typename Epilogue::OutputTileIterator::Layout;
373	            static constexpr int kInterleave = Mma::IteratorB::Shape::kRow / Mma::Shape::kK;
374	            static_assert(platform::is_same<LayoutB, layout::RowMajor>::value && kInterleave == 1
375	                              || platform::is_same<LayoutB, layout::ColumnMajor>::value && kInterleave >= 1,
376	                          "B must be row major/col major OR col major interleaved.");
377	
378	            //
379	            // Problem visitor.
380	            //
381	            ProblemVisitor problem_visitor(params.problem_visitor, shared_storage.problem_visitor, blockIdx.x);
382	
383	            const int64_t gemm_k                  = params.problem_visitor.gemm_k;
384	            const int64_t gemm_n                  = params.problem_visitor.gemm_n;
385	            int64_t       bytes_per_expert_matrix = (gemm_k * gemm_n / 8) * cutlass::sizeof_bits<ElementB>::value;
386	
387	            // Outer 'persistent' loop to iterate over tiles
388	            while (problem_visitor.next_tile()) {
389	
390	                GemmCoord problem_size = problem_visitor.problem_size();
391	                int32_t   problem_idx  = problem_visitor.problem_index();
392	                int32_t   cta_idx      = int32_t(problem_visitor.threadblock_idx());
393	
394	                GemmCoord grid_shape = problem_visitor.grid_shape(problem_size);
395	
396	                cutlass::gemm::GemmCoord threadblock_offset(
397	                    int(cta_idx / grid_shape.n()) * Mma::Shape::kM, int(cta_idx % grid_shape.n()) * Mma::Shape::kN, 0);
398	
399	                // Load element pointers. Exchange pointers and strides if working on the transpose
400	                const int64_t rows_to_jump =
401	                    problem_idx == 0 ? 0 : params.problem_visitor.last_row_for_problem[problem_idx - 1];
402	                ElementA*                   ptr_A = reinterpret_cast<ElementA*>(params.ptr_A) + rows_to_jump * gemm_k;
403	                typename LayoutA::LongIndex ldm_A = gemm_k;
404	
405	                char*                       byte_ptr_B = ((char*)params.ptr_B) + problem_idx * bytes_per_expert_matrix;
406	                ElementB*                   ptr_B      = reinterpret_cast<ElementB*>(byte_ptr_B);
407	                typename LayoutB::LongIndex ldm_B =
408	                    platform::is_same<layout::RowMajor, LayoutB>::value ? gemm_n : gemm_k * kInterleave;
409	
410	                // Compute initial location in logical coordinates
411	                cutlass::MatrixCoord tb_offset_A{
412	                    threadblock_offset.m(),
413	                    0,
414	                };
415	
416	                cutlass::MatrixCoord tb_offset_B{0, threadblock_offset.n() / kInterleave};
417	
418	                cutlass::MatrixCoord tb_offset_scale{0, threadblock_offset.n()};
419	
420	                // Compute position within threadblock
421	                int thread_idx = threadIdx.x;
422	
423	                // Construct iterators to A and B operands
424	                typename Mma::IteratorA iterator_A(
425	                    LayoutA(ldm_A), ptr_A, {problem_size.m(), problem_size.k()}, thread_idx, tb_offset_A);
426	
427	                typename Mma::IteratorB iterator_B(LayoutB(ldm_B),
428	                                                   ptr_B,
429	                                                   {problem_size.k() * kInterleave, problem_size.n() / kInterleave},
430	                                                   thread_idx,
431	                                                   tb_offset_B);
432	
433	                typename Mma::FragmentC accumulators;
434	
435	                accumulators.clear();
436	
437	                // Broadcast the warp_id computed by lane 0 to ensure dependent code
438	                // is compiled as warp-uniform.
439	                int warp_idx = __shfl_sync(0xffffffff, threadIdx.x / 32, 0);
440	
441	                int lane_idx = threadIdx.x % 32;
442	
443	                //
444	                // Matrix multiply phase
445	                //
446	
447	                // Construct thread-scoped matrix multiply
448	                Mma mma(shared_storage.main_loop, thread_idx, warp_idx, lane_idx);
449	
450	                // Compute threadblock-scoped matrix multiply-add
451	                int gemm_k_iterations = (problem_size.k() + Mma::Shape::kK - 1) / Mma::Shape::kK;
452	
453	                // Wait for all threads to finish their epilogue phases from the previous tile.
454	                __syncthreads();
455	
456	                // Compute threadblock-scoped matrix multiply-add
457	                ElementScale* weight_scale_ptr = params.weight_scales + problem_idx * problem_size.n();
458	                run_mma<Mma>(mma,
459	                             gemm_k_iterations,
460	                             accumulators,
461	                             iterator_A,
462	                             iterator_B,
463	                             accumulators,
464	                             weight_scale_ptr,
465	                             {1, problem_size.n()},
466	                             thread_idx,
467	                             tb_offset_scale);
468	
469	                //
470	                // Epilogue
471	                //
472	
473	                EpilogueOutputOp output_op(params.output_op);
474	
475	                ElementC* ptr_C = reinterpret_cast<ElementC*>(params.ptr_C) + problem_idx * gemm_n;
476	                ElementC* ptr_D = reinterpret_cast<ElementC*>(params.ptr_D) + rows_to_jump * gemm_n;
477	
478	                LayoutC layout_C(0);
479	                LayoutC layout_D(gemm_n);
480	
481	                typename Epilogue::OutputTileIterator::Params params_C(layout_C);
482	                typename Epilogue::OutputTileIterator::Params params_D(layout_D);
483	
484	                // Tile iterator loading from source tensor.
485	                typename Epilogue::OutputTileIterator iterator_C(
486	                    params_C, ptr_C, problem_size.mn(), thread_idx, threadblock_offset.mn());
487	
488	                // Tile iterator writing to destination tensor.
489	                typename Epilogue::OutputTileIterator iterator_D(
490	                    params_D, ptr_D, problem_size.mn(), thread_idx, threadblock_offset.mn());
491	
492	                Epilogue epilogue(shared_storage.epilogue, thread_idx, warp_idx, lane_idx);
493	
494	                // Execute the epilogue operator to update the destination tensor.
495	                epilogue(output_op, iterator_D, accumulators, iterator_C);
496	
497	                // Next tile
498	                problem_visitor.advance(gridDim.x);
499	            }
500	        }
501	    };
502	
503	    /*
504	      To improve compilation speed, we do not compile the device operator if the CUDA_ARCH does not correspond
505	      to the ArchTag of the cutlass kernel operator.
506	    */
507	    /// Executes one GEMM
508	    CUTLASS_DEVICE
509	    void operator()(Params const& params, SharedStorage& shared_storage)
510	    {
511	#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 700) && (__CUDA_ARCH__ < 750)
512	        static constexpr bool compile_needed = platform::is_same<KernelArch, arch::Sm70>::value;
513	        KernelRunner<compile_needed>::run_kernel(params, shared_storage);
514	#elif defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 750) && (__CUDA_ARCH__ < 800)
515	        static constexpr bool compile_needed = platform::is_same<KernelArch, arch::Sm75>::value;
516	        KernelRunner<compile_needed>::run_kernel(params, shared_storage);
517	#elif defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800) && (__CUDA_ARCH__ < 900)
518	        static constexpr bool compile_needed = platform::is_same<KernelArch, arch::Sm80>::value;
519	        KernelRunner<compile_needed>::run_kernel(params, shared_storage);
520	#else
521	        CUTLASS_NOT_IMPLEMENTED();
522	#endif
523	    }
524	};
525	
526	/////////////////////////////////////////////////////////////////////////////////////////////////
527	
528	}  // namespace kernel
529	}  // namespace gemm
530	}  // namespace cutlass
