46	/////////////////////////////////////////////////////////////////////////////////////////////////
47	
48	/// Visitor class to abstract away the algorithm for iterating over tiles
49	template<typename ProblemSizeHelper, typename ThreadblockShape_>
50	struct BaseMoeProblemVisitor {
51	    using ThreadblockShape = ThreadblockShape_;
52	
53	    struct ProblemInfo {
54	        static int32_t const kNoPrefetchEntry = -1;
55	        int32_t              problem_idx;
56	        int32_t              problem_start;
57	
58	        CUTLASS_DEVICE
59	        ProblemInfo(): problem_idx(kNoPrefetchEntry), problem_start(kNoPrefetchEntry) {}
60	
61	        CUTLASS_DEVICE
62	        ProblemInfo(int32_t problem_idx_, int32_t problem_start_):
63	            problem_idx(problem_idx_), problem_start(problem_start_)
64	        {
65	        }
66	    };
67	
68	    struct Params {
69	        int64_t const* last_row_for_problem;
70	        int64_t        gemm_n;
71	        int64_t        gemm_k;
72	        int32_t        problem_count;
73	        void const*    workspace;
74	        int32_t        tile_count;
75	
76	        //
77	        // Methods
78	        //
79	
80	        /// Ctor
81	        CUTLASS_HOST_DEVICE
82	        Params():
83	            last_row_for_problem(nullptr), gemm_n(0), gemm_k(0), problem_count(0), workspace(nullptr), tile_count(0)
84	        {
85	        }
86	
87	        /// Ctor
88	        CUTLASS_HOST_DEVICE
89	        Params(int64_t const* last_row_for_problem,
90	               int64_t        gemm_n,
91	               int64_t        gemm_k,
92	               int32_t        problem_count,
93	               void const*    workspace  = nullptr,
94	               int32_t        tile_count = 0):
95	            last_row_for_problem(last_row_for_problem),
96	            gemm_n(gemm_n),
97	            gemm_k(gemm_k),
98	            problem_count(problem_count),
99	            workspace(workspace),
100	            tile_count(tile_count)
101	        {
102	        }
103	    };
104	
105	    Params const& params;
106	    int32_t       tile_idx;
107	    int32_t       problem_tile_start;
108	    int32_t       problem_idx;
109	
110	    //
111	    // Methods
112	    //
113	    CUTLASS_DEVICE
114	    BaseMoeProblemVisitor(Params const& params_, int32_t block_idx):
115	        params(params_), tile_idx(block_idx), problem_tile_start(0), problem_idx(0)
116	    {
117	    }
118	
119	    /// Get the grid shape
120	    CUTLASS_HOST_DEVICE
121	    static cutlass::gemm::GemmCoord grid_shape(const cutlass::gemm::GemmCoord& problem)
122	    {
123	
124	        return cutlass::gemm::GemmCoord(((problem.m() - 1 + ThreadblockShape::kM) / ThreadblockShape::kM),
125	                                        ((problem.n() - 1 + ThreadblockShape::kN) / ThreadblockShape::kN),
126	                                        1);
127	    }
128	
129	    /// Gets the global tile index
130	    CUTLASS_HOST_DEVICE
131	    int32_t tile_index() const
132	    {
133	        return tile_idx;
134	    }
135	
136	    /// Gets the index of the problem
137	    CUTLASS_HOST_DEVICE
138	    int32_t problem_index() const
139	    {
140	        return problem_idx;
141	    }
142	
143	    CUTLASS_HOST_DEVICE
144	    int32_t threadblock_idx() const
145	    {
146	        return tile_idx - problem_tile_start;
147	    }
148	
149	    CUTLASS_DEVICE
150	    void advance(int32_t grid_size)
151	    {
152	        tile_idx += grid_size;
153	    }
154	
155	    CUTLASS_HOST_DEVICE
156	    static void possibly_transpose_problem(cutlass::gemm::GemmCoord& problem)
157	    {
158	        ProblemSizeHelper::possibly_transpose_problem(problem);
159	    }
160	
161	    /// Returns the problem size for the current problem
162	    CUTLASS_HOST_DEVICE
163	    cutlass::gemm::GemmCoord problem_size() const
164	    {
165	        return problem_size(problem_idx);
166	    }
167	
168	    CUTLASS_HOST_DEVICE
169	    cutlass::gemm::GemmCoord problem_size(int idx) const
170	    {
171	        const int64_t prev_problem_row    = idx == 0 ? 0 : params.last_row_for_problem[idx - 1];
172	        const int64_t current_problem_row = params.last_row_for_problem[idx];
173	        const int64_t gemm_m              = current_problem_row - prev_problem_row;
174	        GemmCoord problem(GemmCoord::Index(gemm_m), GemmCoord::Index(params.gemm_n), GemmCoord::Index(params.gemm_k));
175	        ProblemSizeHelper::possibly_transpose_problem(problem);
176	        return problem;
177	    }
178	
179	    CUTLASS_HOST_DEVICE
180	    static int32_t tile_count(const cutlass::gemm::GemmCoord& grid)
181	    {
182	        return ProblemSizeHelper::tile_count(grid);
183	    }
184	
185	    static int32_t group_tile_count(const cutlass::gemm::GemmCoord* host_problem_sizes_ptr, int32_t problem_count)
186	    {
187	        int32_t total_tiles = 0;
188	        for (int32_t i = 0; i < problem_count; ++i) {
189	            auto problem = host_problem_sizes_ptr[i];
190	            possibly_transpose_problem(problem);
191	            auto grid = grid_shape(problem);
192	            total_tiles += tile_count(grid);
193	        }
194	
195	        return total_tiles;
196	    }
197	};
198	
199	/////////////////////////////////////////////////////////////////////////////////////////////////
200	
201	template<typename ProblemSizeHelper,
202	         typename ThreadblockShape,
203	         GroupScheduleMode GroupScheduleMode_,
204	         int               PrefetchTileCount,
205	         int               ThreadCount>
206	struct MoeProblemVisitor;
207	
208	/////////////////////////////////////////////////////////////////////////////////////////////////
209	// ProblemVisitor that performs all scheduling on device
210	//
211	template<typename ProblemSizeHelper, typename ThreadblockShape, int PrefetchTileCount, int ThreadCount>
212	struct MoeProblemVisitor<ProblemSizeHelper,
213	                         ThreadblockShape,
214	                         GroupScheduleMode::kDeviceOnly,
215	                         PrefetchTileCount,
216	                         ThreadCount>: public BaseMoeProblemVisitor<ProblemSizeHelper, ThreadblockShape> {
217	    using Base                                = BaseMoeProblemVisitor<ProblemSizeHelper, ThreadblockShape>;
218	    using Params                              = typename Base::Params;
219	    static int const  kThreadCount            = ThreadCount;
220	    static bool const kRequiresPrecomputation = false;
221	    static int const  kThreadsPerWarp         = 32;
222	
223	    struct SharedStorage {};
224	
225	    // Final tile of the problem loaded by this thread. Each thread will hold
226	    // a separate value.
227	    int32_t problem_ending_tile;
228	
229	    SharedStorage& shared_storage;
230	
231	    //
232	    // Methods
233	    //
234	    CUTLASS_DEVICE
235	    MoeProblemVisitor(Params const& params_, SharedStorage& shared_storage_, int32_t block_idx):
236	        Base(params_, block_idx), problem_ending_tile(0), shared_storage(shared_storage_)
237	    {
238	        this->problem_idx        = -1 * kThreadsPerWarp;
239	        this->problem_tile_start = 0;
240	    }
241	
242	    CUTLASS_DEVICE
243	    bool next_tile()
244	    {
245	        // Check whether the tile to compute is within the range of the current problem.
246	        int32_t problem_tile_end = __shfl_sync(0xffffffff, problem_ending_tile, this->problem_idx % kThreadsPerWarp);
247	        if (this->tile_idx < problem_tile_end) {
248	            return true;
249	        }
250	
251	        // Check whether the tile to compute is within the current group of problems fetched by the warp.
252	        // The last tile for this group is the final tile of the problem held by the final thread in the warp.
253	        int32_t group_tile_end = __shfl_sync(0xffffffff, problem_ending_tile, kThreadsPerWarp - 1);
254	
255	        // Keep the starting problem for this group in `problem_idx`. This is done to reduce
256	        // register pressure. The starting problem for this group is simply the first problem
257	        // in the group most recently fetched by the warp.
258	        int32_t& group_problem_start = this->problem_idx;
259	        group_problem_start          = (this->problem_idx / kThreadsPerWarp) * kThreadsPerWarp;
260	
261	        // Keep the starting tile for this group in `problem_tile_start`. This is done to reduce
262	        // register pressure.
263	        int32_t& group_tile_start = this->problem_tile_start;
264	
265	        // Each thread in the warp processes a separate problem to advance until
266	        // reaching a problem whose starting tile is less less than tile_idx.
267	        while (group_tile_end <= this->tile_idx) {
268	            group_problem_start += kThreadsPerWarp;
269	            if (group_problem_start > this->params.problem_count) {
270	                return false;
271	            }
272	
273	            // Since `group_tile_start` is a reference to `this->problem_tile_start`, this
274	            // also sets `this->problem_tile_start`. The fact that `this->problem_tile_start`
275	            // is also set here is used later in `next_tile`.
276	            group_tile_start = group_tile_end;
277	
278	            int     lane_idx     = threadIdx.x % kThreadsPerWarp;
279	            int32_t lane_problem = group_problem_start + lane_idx;
280	
281	            // Compute the number of tiles in the problem assigned to each thread.
282	            problem_ending_tile = 0;
283	            if (lane_problem < this->params.problem_count) {
284	                cutlass::gemm::GemmCoord problem = this->problem_size(lane_problem);
285	                cutlass::gemm::GemmCoord grid    = this->grid_shape(problem);
286	                problem_ending_tile              = this->tile_count(grid);
287	            }
288	
289	            // Compute a warp-wide inclusive prefix sum to compute the ending tile index of
290	            // each thread's problem.
291	            CUTLASS_PRAGMA_UNROLL
292	            for (int i = 1; i < kThreadsPerWarp; i <<= 1) {
293	                int32_t val = __shfl_up_sync(0xffffffff, problem_ending_tile, i);
294	                if (lane_idx >= i) {
295	                    problem_ending_tile += val;
296	                }
297	            }
298	
299	            // The total tile count for this group is now in the final position of the prefix sum
300	            int32_t tiles_in_group = __shfl_sync(0xffffffff, problem_ending_tile, kThreadsPerWarp - 1);
301	
302	            problem_ending_tile += group_tile_start;
303	            group_tile_end += tiles_in_group;
304	        }
305	
306	        // The next problem to process is the first one that does not have ending tile position
307	        // that is greater than or equal to tile index.
308	        int32_t problem_idx_in_group = __popc(__ballot_sync(0xffffffff, problem_ending_tile <= this->tile_idx));
309	
310	        this->problem_idx = group_problem_start + problem_idx_in_group;
311	
312	        // The starting tile for this problem is the ending tile of the previous problem. In cases
313	        // where `problem_idx_in_group` is the first problem in the group, we do not need to reset
314	        // `problem_tile_start`, because it is set to the previous group's ending tile in the while
315	        // loop above.
316	        if (problem_idx_in_group > 0) {
317	            this->problem_tile_start = __shfl_sync(0xffffffff, problem_ending_tile, problem_idx_in_group - 1);
318	        }
319	
320	        return true;
321	    }
322	
323	    static size_t get_workspace_size(const cutlass::gemm::GemmCoord* host_problem_sizes_ptr,
324	                                     int32_t                         problem_count,
325	                                     int32_t                         block_count)
326	    {
327	        return 0;
328	    }
329	
330	    static void host_precompute(const cutlass::gemm::GemmCoord* host_problem_sizes_ptr,
331	                                int32_t                         problem_count,
332	                                int32_t                         block_count,
333	                                void*                           host_workspace_ptr)
334	    {
335	    }
336	};
337	
338	}  // namespace kernel
339	}  // namespace gemm
340	}  // namespace cutlass
